import { SeedApiClient } from "../../../src/Client";
import { mockServerPool } from "../../mock-server/MockServerPool";

describe("AuthClient", () => {
    test("gettoken", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({
            maxRetries: 0,
            token: "test",
            apiVersion: "test",
            apiKey: "test",
            environment: { base: server.baseUrl, auth: server.baseUrl, upload: server.baseUrl },
        });
        const rawRequestBody = { client_id: "client_id", client_secret: "client_secret" };
        const rawResponseBody = { access_token: "access_token" };

        server
            .mockEndpoint()
            .post("/oauth/token")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.multiUrlEnvironmentReference.auth.gettoken({
            clientId: "client_id",
            clientSecret: "client_secret",
        });
        expect(response).toEqual({
            body: {
                accessToken: "access_token",
            },
            ok: true,
            headers: expect.any(Object),
            rawResponse: expect.any(Object),
        });
    });
});
